2	//
3	// aes_encipher_block.v
4	// --------------------
5	// The AES encipher round. A pure combinational module that implements
6	// the initial round, main round and final round logic for
7	// enciper operations.
8	//
9	//======================================================================
10	
11	module aes_encipher_block(
12	                          input wire            clk,
13	                          input wire            reset_n,
14	
15	                          input wire            next,
16	
17	                          input wire            keylen,
18	                          output wire [3 : 0]   round,
19	                          input wire [127 : 0]  round_key,
20	
21	                          output wire [31 : 0]  sboxw,
22	                          input wire  [31 : 0]  new_sboxw,
23	
24	                          input wire [127 : 0]  block,
25	                          output wire [127 : 0] new_block,
26	                          output wire           ready
27	                         );
28	
29	
30	  //----------------------------------------------------------------
31	  // Internal constant and parameter definitions.
32	  //----------------------------------------------------------------
33	  localparam AES_128_BIT_KEY = 1'h0;
34	  localparam AES_256_BIT_KEY = 1'h1;
35	
36	  localparam AES128_ROUNDS = 4'ha;
37	  localparam AES256_ROUNDS = 4'he;
38	
39	  localparam NO_UPDATE    = 3'h0;
40	  localparam INIT_UPDATE  = 3'h1;
41	  localparam SBOX_UPDATE  = 3'h2;
42	  localparam MAIN_UPDATE  = 3'h3;
43	  localparam FINAL_UPDATE = 3'h4;
44	
45	  localparam CTRL_IDLE  = 3'h0;
46	  localparam CTRL_INIT  = 3'h1;
47	  localparam CTRL_SBOX  = 3'h2;
48	  localparam CTRL_MAIN  = 3'h3;
49	  localparam CTRL_FINAL = 3'h4;
50	
51	
52	  //----------------------------------------------------------------
53	  // Round functions with sub functions.
54	  //----------------------------------------------------------------
55	  function [7 : 0] gm2(input [7 : 0] op);
56	    begin
57	      gm2 = {op[6 : 0], 1'b0} ^ (8'h1b & {8{op[7]}});
58	    end
59	  endfunction // gm2
60	
61	  function [7 : 0] gm3(input [7 : 0] op);
62	    begin
63	      gm3 = gm2(op) ^ op;
64	    end
65	  endfunction // gm3
66	
67	  function [31 : 0] mixw(input [31 : 0] w);
68	    reg [7 : 0] b0, b1, b2, b3;
69	    reg [7 : 0] mb0, mb1, mb2, mb3;
70	    begin
71	      b0 = w[31 : 24];
72	      b1 = w[23 : 16];
73	      b2 = w[15 : 08];
74	      b3 = w[07 : 00];
75	
76	      mb0 = gm2(b0) ^ gm3(b1) ^ b2      ^ b3;
77	      mb1 = b0      ^ gm2(b1) ^ gm3(b2) ^ b3;
78	      mb2 = b0      ^ b1      ^ gm2(b2) ^ gm3(b3);
79	      mb3 = gm3(b0) ^ b1      ^ b2      ^ gm2(b3);
80	
81	      mixw = {mb0, mb1, mb2, mb3};
82	    end
83	  endfunction // mixw
84	
85	  function [127 : 0] mixcolumns(input [127 : 0] data);
86	    reg [31 : 0] w0, w1, w2, w3;
87	    reg [31 : 0] ws0, ws1, ws2, ws3;
88	    begin
89	      w0 = data[127 : 096];
90	      w1 = data[095 : 064];
91	      w2 = data[063 : 032];
92	      w3 = data[031 : 000];
93	
94	      ws0 = mixw(w0);
95	      ws1 = mixw(w1);
96	      ws2 = mixw(w2);
97	      ws3 = mixw(w3);
98	
99	      mixcolumns = {ws0, ws1, ws2, ws3};
100	    end
101	  endfunction // mixcolumns
102	
103	  function [127 : 0] shiftrows(input [127 : 0] data);
104	    reg [31 : 0] w0, w1, w2, w3;
105	    reg [31 : 0] ws0, ws1, ws2, ws3;
106	    begin
107	      w0 = data[127 : 096];
108	      w1 = data[095 : 064];
109	      w2 = data[063 : 032];
110	      w3 = data[031 : 000];
111	
112	      ws0 = {w0[31 : 24], w1[23 : 16], w2[15 : 08], w3[07 : 00]};
113	      ws1 = {w1[31 : 24], w2[23 : 16], w3[15 : 08], w0[07 : 00]};
114	      ws2 = {w2[31 : 24], w3[23 : 16], w0[15 : 08], w1[07 : 00]};
115	      ws3 = {w3[31 : 24], w0[23 : 16], w1[15 : 08], w2[07 : 00]};
116	
117	      shiftrows = {ws0, ws1, ws2, ws3};
118	    end
119	  endfunction // shiftrows
120	
121	  function [127 : 0] addroundkey(input [127 : 0] data, input [127 : 0] rkey);
122	    begin
123	      addroundkey = data ^ rkey;
124	    end
125	  endfunction // addroundkey
126	
127	
128	  //----------------------------------------------------------------
129	  // Registers including update variables and write enable.
130	  //----------------------------------------------------------------
131	  reg [1 : 0]   sword_ctr_reg;
132	  reg [1 : 0]   sword_ctr_new;
133	  reg           sword_ctr_we;
134	  reg           sword_ctr_inc;
135	  reg           sword_ctr_rst;
