140	  reg           round_ctr_rst;
141	  reg           round_ctr_inc;
142	
143	  reg [127 : 0] block_new;
144	  reg [31 : 0]  block_w0_reg;
145	  reg [31 : 0]  block_w1_reg;
146	  reg [31 : 0]  block_w2_reg;
147	  reg [31 : 0]  block_w3_reg;
