150	  reg           block_w2_we;
151	  reg           block_w3_we;
152	
153	  reg           ready_reg;
154	  reg           ready_new;
155	  reg           ready_we;
156	
157	  reg [2 : 0]   enc_ctrl_reg;
158	  reg [2 : 0]   enc_ctrl_new;
159	  reg           enc_ctrl_we;
160	
161	
