166	  reg [31 : 0] muxed_sboxw;
167	
168	
169	  //----------------------------------------------------------------
170	  // Concurrent connectivity for ports etc.
171	  //----------------------------------------------------------------
172	  assign round     = round_ctr_reg;
173	  assign sboxw     = muxed_sboxw;
174	  assign new_block = {block_w0_reg, block_w1_reg, block_w2_reg, block_w3_reg};
