178	  //----------------------------------------------------------------
179	  // reg_update
180	  //
181	  // Update functionality for all registers in the core.
182	  // All registers are positive edge triggered with asynchronous
183	  // active low reset. All registers have write enable.
184	  //----------------------------------------------------------------
185	  always @ (posedge clk or negedge reset_n)
186	    begin: reg_update
187	      if (!reset_n)
188	        begin
189	          block_w0_reg  <= 32'h0;
190	          block_w1_reg  <= 32'h0;
191	          block_w2_reg  <= 32'h0;
192	          block_w3_reg  <= 32'h0;
193	          sword_ctr_reg <= 2'h0;
194	          round_ctr_reg <= 4'h0;
195	          ready_reg     <= 1'b1;
